inputs.script:
const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\s+/g, ' ').trim();
const rawAction = cleanArg(arg0).toLowerCase();
const action = rawAction === 'unlike' ? 'unlike' : 'like';
const postUrl = cleanArg(arg1);
const bodyText = normalize(document.body?.innerText || '');
if (/login|log in|sign up/i.test(document.title) || document.querySelector('input[name="username"], input[name="enc_password"]')) return { post_url: postUrl, action, status: 'login_required', url: location.href };
if (/sorry, this page isn't available|page isn't available|user not found/i.test(bodyText)) return { post_url: postUrl, action, status: 'not_found', url: location.href };
const article = document.querySelector('article') || document.querySelector('main');
if (!article) return { post_url: postUrl, action, status: 'action_bar_not_found', reason: 'no article', url: location.href };
const commentSvg = article.querySelector('svg[aria-label="Comment"]');
if (!commentSvg) return { post_url: postUrl, action, status: 'action_bar_not_found', reason: 'no Comment svg', url: location.href };
const commentBtn = commentSvg.closest('[role="button"], button, a');
if (!commentBtn) return { post_url: postUrl, action, status: 'action_bar_not_found', reason: 'Comment not clickable', url: location.href };
let actionBar = commentBtn.parentElement;
let likeSvg = null;
for (let depth = 0; depth < 6 && actionBar; depth += 1) {
  const candidates = actionBar.querySelectorAll('svg[aria-label="Like"], svg[aria-label="Unlike"]');
  if (candidates.length === 1) { likeSvg = candidates[0]; break; }
  actionBar = actionBar.parentElement;
}
if (!likeSvg) return { post_url: postUrl, action, status: 'action_bar_not_found', reason: 'no unique Like svg near Comment', url: location.href };
const beforeLabel = likeSvg.getAttribute('aria-label');
const currentState = beforeLabel === 'Unlike' ? 'liked' : 'unliked';
if (action === 'like' && currentState === 'liked') return { post_url: postUrl, action, status: 'already_liked', before_label: beforeLabel, url: location.href };
if (action === 'unlike' && currentState === 'unliked') return { post_url: postUrl, action, status: 'already_unliked', before_label: beforeLabel, url: location.href };
const likeBtn = likeSvg.closest('[role="button"], button, a') || likeSvg.parentElement;
if (!likeBtn) return { post_url: postUrl, action, status: 'click_failed', reason: 'Like not clickable', before_label: beforeLabel, url: location.href };
likeBtn.scrollIntoView({ block: 'center', inline: 'center' });
try { likeBtn.focus?.({ preventScroll: true }); } catch {}
try { likeBtn.click(); } catch {}
for (const type of ['pointerdown','mousedown','pointerup','mouseup','click']) {
  try {
    const Ctor = type.startsWith('pointer') && typeof PointerEvent !== 'undefined' ? PointerEvent : MouseEvent;
    likeBtn.dispatchEvent(new Ctor(type, { bubbles: true, cancelable: true, composed: true, view: window, button: 0, buttons: 1, pointerType: 'mouse' }));
  } catch {}
}
await sleep(800);
const refreshedCandidates = actionBar.querySelectorAll('svg[aria-label="Like"], svg[aria-label="Unlike"]');
const refreshedSvg = refreshedCandidates.length === 1 ? refreshedCandidates[0] : null;
const afterLabel = refreshedSvg?.getAttribute('aria-label') || null;
const newState = afterLabel === 'Unlike' ? 'liked' : afterLabel === 'Like' ? 'unliked' : 'unknown';
if (action === 'like' && newState === 'liked') return { post_url: postUrl, action, status: 'liked', before_label: beforeLabel, after_label: afterLabel, url: location.href };
if (action === 'unlike' && newState === 'unliked') return { post_url: postUrl, action, status: 'unliked', before_label: beforeLabel, after_label: afterLabel, url: location.href };
return { post_url: postUrl, action, status: 'click_failed', before_label: beforeLabel, after_label: afterLabel, url: location.href };
